import{_ as e,o as d,c as a,ae as o}from"./chunks/framework.B6gjLfeO.js";const _=JSON.parse('{"title":"Traps","description":"","frontmatter":{},"headers":[],"relativePath":"traps.md","filePath":"traps.md"}'),r={name:"traps.md"};function n(s,t,i,c,p,h){return d(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="traps" tabindex="-1">Traps <a class="header-anchor" href="#traps" aria-label="Permalink to &quot;Traps&quot;">​</a></h1><p>A trap is a realistic-looking login page served at a URL that legitimate users would never visit. When a scanner or attacker hits the URL, NotTodayHoney records the event and classifies it.</p><h2 id="wordpress-trap" tabindex="-1">WordPress Trap <a class="header-anchor" href="#wordpress-trap" aria-label="Permalink to &quot;WordPress Trap&quot;">​</a></h2><p>Simulates the WordPress <code>wp-login.php</code> login page, including the spoofed version number in the HTML.</p><p><strong>Route:</strong> <code>GET /wp-login.php</code>, <code>POST /wp-login.php</code></p><p><strong>Environment variables:</strong></p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>NOT_TODAY_HONEY_WP_ENABLED</code></td><td><code>true</code></td><td>Enable/disable the trap</td></tr><tr><td><code>NOT_TODAY_HONEY_WP_PATH</code></td><td><code>/wp-admin</code></td><td>Mount path</td></tr><tr><td><code>NOT_TODAY_HONEY_WP_LOGIN_SUCCESS_BEHAVIOR</code></td><td><code>fake_success</code></td><td>Response after a login attempt</td></tr><tr><td><code>NOT_TODAY_HONEY_WP_VERSION</code></td><td><code>6.4.2</code></td><td>Spoofed WP version shown in the page</td></tr></tbody></table><h2 id="phpmyadmin-trap" tabindex="-1">phpMyAdmin Trap <a class="header-anchor" href="#phpmyadmin-trap" aria-label="Permalink to &quot;phpMyAdmin Trap&quot;">​</a></h2><p>Simulates the phpMyAdmin login screen.</p><p><strong>Default URL:</strong> <code>/phpmyadmin</code></p><p><strong>Environment variables:</strong></p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>NOT_TODAY_HONEY_PMA_ENABLED</code></td><td><code>true</code></td><td>Enable/disable the trap</td></tr><tr><td><code>NOT_TODAY_HONEY_PMA_PATH</code></td><td><code>/phpmyadmin</code></td><td>Mount path</td></tr><tr><td><code>NOT_TODAY_HONEY_PMA_LOGIN_SUCCESS_BEHAVIOR</code></td><td><code>fake_success</code></td><td>Response after a login attempt</td></tr><tr><td><code>NOT_TODAY_HONEY_PMA_VERSION</code></td><td><code>5.2.1</code></td><td>Spoofed PMA version shown in the page</td></tr></tbody></table><h2 id="generic-admin-trap" tabindex="-1">Generic Admin Trap <a class="header-anchor" href="#generic-admin-trap" aria-label="Permalink to &quot;Generic Admin Trap&quot;">​</a></h2><p>A generic control panel login page. The title is configurable to match whatever your attacker is scanning for.</p><p><strong>Default URL:</strong> <code>/admin/login</code></p><p><strong>Environment variables:</strong></p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>NOT_TODAY_HONEY_GENERIC_ENABLED</code></td><td><code>true</code></td><td>Enable/disable the trap</td></tr><tr><td><code>NOT_TODAY_HONEY_GENERIC_PATH</code></td><td><code>/admin</code></td><td>Mount path (login served at <code>{path}/login</code>)</td></tr><tr><td><code>NOT_TODAY_HONEY_GENERIC_LOGIN_SUCCESS_BEHAVIOR</code></td><td><code>fake_success</code></td><td>Response after a login attempt</td></tr><tr><td><code>NOT_TODAY_HONEY_GENERIC_TITLE</code></td><td><code>Control Panel</code></td><td>Page title shown in the login form</td></tr></tbody></table><h2 id="login-success-behaviors" tabindex="-1">Login Success Behaviors <a class="header-anchor" href="#login-success-behaviors" aria-label="Permalink to &quot;Login Success Behaviors&quot;">​</a></h2><p>When an attacker submits the login form, the <code>login_success_behavior</code> value controls what they see:</p><table tabindex="0"><thead><tr><th>Value</th><th>HTTP Status</th><th>Effect</th></tr></thead><tbody><tr><td><code>fake_success</code></td><td>200</td><td>Renders an empty dashboard — attacker thinks they&#39;re in</td></tr><tr><td><code>403</code></td><td>403 Forbidden</td><td>Standard access denied response</td></tr><tr><td><code>500</code></td><td>500 Internal Server Error</td><td>Simulates a server crash</td></tr><tr><td><code>infinite_loading</code></td><td>—</td><td>Tarpitting: the response hangs until the request times out</td></tr></tbody></table><p>Configure per trap in <code>.env</code>:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NOT_TODAY_HONEY_WP_LOGIN_SUCCESS_BEHAVIOR=fake_success</span></span>
<span class="line"><span>NOT_TODAY_HONEY_PMA_LOGIN_SUCCESS_BEHAVIOR=403</span></span>
<span class="line"><span>NOT_TODAY_HONEY_GENERIC_LOGIN_SUCCESS_BEHAVIOR=infinite_loading</span></span></code></pre></div>`,22)])])}const u=e(r,[["render",n]]);export{_ as __pageData,u as default};
